"""Generated by w2a — entrypoint for "PR Summary Generator" (sequential).

Trigger: A new pull request is opened or updated.
"""

from __future__ import annotations

import sys
from pathlib import Path

from crew import build_crew, task_analyze_pr, task_write_pr_comment

_TASK_IDS = ['analyze_pr', 'write_pr_comment', ]
_TASK_VARS = {
    'analyze_pr': task_analyze_pr,
    'write_pr_comment': task_write_pr_comment,
}


def _log(event: str, task_id: str) -> None:
    print(f"[w2a] {event} task={task_id}", flush=True)


def _wire_callbacks() -> None:
    for task_id, task in _TASK_VARS.items():
        task.callback = lambda output, _id=task_id: _log("TASK_END", _id)


def _read_input(source: str) -> str:
    if source == "-":
        return sys.stdin.read()
    return Path(source).read_text(encoding="utf-8")


def main() -> int:
    source = sys.argv[1] if len(sys.argv) > 1 else "-"
    payload = _read_input(source)

    _wire_callbacks()
    for task_id in _TASK_IDS:
        _log("TASK_START", task_id)

    crew = build_crew()
    result = crew.kickoff(inputs={"input": payload})

    print("\n--- RESULT ---")
    print(result.raw)
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
